const countries = ($json.countries || []).map(c => String(c));
const officialVisaSources = {
  'United States': ['https://travel.state.gov/content/travel/en/us-visas/study/student-visa.html','https://www.uscis.gov/working-in-the-united-states/students-and-exchange-visitors/students-and-employment'],
  'United Kingdom': ['https://www.gov.uk/student-visa','https://www.gov.uk/graduate-visa'],
  'Canada': ['https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit.html'],
  'Australia': ['https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/student-500'],
  'Germany': ['https://www.make-it-in-germany.com/en/visa-residence/types/studying'],
  'France': ['https://france-visas.gouv.fr/en/web/france-visas/student'],
  'Netherlands': ['https://ind.nl/en/study'],
  'Ireland': ['https://www.irishimmigration.ie/coming-to-study-in-ireland/'],
  'New Zealand': ['https://www.immigration.govt.nz/new-zealand-visas/visas/visa/fee-paying-student-visa'],
  'Singapore': ['https://www.ica.gov.sg/reside/STP/apply'],
  'Japan': ['https://www.mofa.go.jp/j_info/visit/visa/long/visa6.html'],
  'Sweden': ['https://www.migrationsverket.se/English/Private-individuals/Studying-in-Sweden.html'],
  'Norway': ['https://www.udi.no/en/want-to-apply/studies/studietillatelse/'],
  'Denmark': ['https://www.nyidanmark.dk/en-GB/You-want-to-apply/Study'],
  'Finland': ['https://migri.fi/en/studying-in-finland'],
  'UAE': ['https://u.ae/en/information-and-services/education/higher-education/student-visa']
};
const out = [];
for (const country of countries) {
  const urls = officialVisaSources[country] || [];
  for (const url of urls) {
    out.push({ json: { country, url, sourceType: 'official_visa' } });
  }
}
return out;

function checksum(str){let h=0;for(let i=0;i<str.length;i++){h=((h<<5)-h)+str.charCodeAt(i);h|=0;}return String(h);}
const body = String($json.body || '');
const statusCode = Number($json.statusCode || 0);
const key = $item(0).$node['Split In Batches'].json.country + '::' + $item(0).$node['Split In Batches'].json.url;
const staticData = getWorkflowStaticData('global');
const hashes = staticData.visaHashes || {};
const newHash = checksum(body.slice(0, 200000));
const oldHash = hashes[key];
const changed = statusCode >= 200 && statusCode < 300 && newHash !== oldHash;
if (changed) hashes[key] = newHash;
staticData.visaHashes = hashes;
return [{json: {country: $item(0).$node['Split In Batches'].json.country, url: $item(0).$node['Split In Batches'].json.url, statusCode, changed}}];
